#[test]
fn test_ref_kuramoto_small_final_state() {
    let (expected_flat, expected_shape) = load_ref_npy("single_sim/kuramoto_small_final_state.npy");

    let cfg = SimConfig {
        sim_length: 10.0,
        dt: 0.1,
        integrator: IntegratorKind::Euler,
        nsig: crate::config::NsigConfig::Scalar(0.0),
        network: NetworkConfig {
            subnetworks: vec![SubnetworkConfig {
                model: "Kuramoto".to_string(),
                nnodes: 2,
                nmodes: 1,
                initial_state: InitialStateConfig::Inline(vec![0.0, 0.0]),
                params: hyburn::model::kuramoto_model::kuramoto_default_params(),
            }],
            projections: vec![],
        },
        monitors: vec![],
        stimuli: vec![],
    };

    let device = Default::default();
    let mut engine = HybridEngine::<B>::from_config(cfg, device)
        .expect("Engine creation failed");
    engine.run(100);

    let (actual_flat, actual_shape) = hyburn::io::tensor_to_flat_f32(engine.states[0].clone());
    assert_eq!(actual_shape, expected_shape,
        "Shape mismatch: actual={:?} expected={:?}", actual_shape, expected_shape);

    // Kuramoto phase wraps to [0, 2π) in hyburn, TVB doesn't.
    // After 100 steps with ω=1, dt=0.1: phase = 0 + 100*0.1*1.0 = 10.0
    // hyburn wraps: 10.0 mod 2π ≈ 10.0 - 3*2π = 10.0 - 18.85 ≈ -8.85 → +2π ≈ 10.0 - 6.283 = 3.717
    // TVB: 10.0 (no wrapping)
    // So we need to compare with wrapping tolerance.
    // For phase variables, compare mod 2π.
    let two_pi = 2.0 * std::f32::consts::PI;
    for (i, (&a, &e)) in actual_flat.iter().zip(expected_flat.iter()).enumerate() {
        let a_wrapped = ((a % two_pi) + two_pi) % two_pi;
        let e_wrapped = ((e % two_pi) + two_pi) % two_pi;
        let diff = (a_wrapped - e_wrapped).abs().min(two_pi - (a_wrapped - e_wrapped).abs());
        assert!(
            diff < 1e-3,
            "kuramoto phase mismatch at {}: actual={:.6} (wrapped={:.6}), expected={:.6} (wrapped={:.6}), diff={:.6}",
            i, a, a_wrapped, e, e_wrapped, diff
        );
    }
}

